class Playground {
    constructor(slots) {
        this.arr = slots.arr;
        this.deque = slots.deque;
        this.res = slots.res;
    }

    async run(inputs) {
        const nums = inputs.nums;
        const k = inputs.k;

        this.arr.init(nums);
        this.deque.init([]);
        this.res.init([]);
        log(`Starting Sliding Window Max with K=${k}`);
        await awaitStep();

        const result = [];
        for (let i = 0; i < nums.length; i++) {
            this.arr.highlight(i, '#3b82f6');
            log(`Processing index ${i} (val ${nums[i]})`);

            // 1. Remove indices out of window
            if (!this.deque.isEmpty() && this.deque.peekFront() <= i - k) {
                log(`Index ${this.deque.peekFront()} is outside window. Removing from front.`);
                this.deque.highlight(0, '#ef4444');
                await awaitStep();
                this.deque.popFront();
                log(`Deque: [${this.deque.data.join(', ')}]`);
                await awaitStep();
            }

            // 2. Maintain Monotonic property (descending)
            while (!this.deque.isEmpty() && nums[this.deque.peekBack()] < nums[i]) {
                log(`Back index ${this.deque.peekBack()} (val ${nums[this.deque.peekBack()]}) < ${nums[i]}. Removing.`);
                this.deque.highlight(this.deque.size() - 1, '#ef4444');
                this.arr.highlight(this.deque.peekBack(), '#ef4444');
                await awaitStep();
                this.deque.popBack();
                this.arr.render(); // Reset colors
                this.arr.highlight(i, '#3b82f6');
            }

            this.deque.pushBack(i);
            this.deque.highlight(this.deque.size() - 1, '#10b981');
            log(`Added index ${i} to deque.`);
            await awaitStep();

            // 3. Add to result if window is full
            if (i >= k - 1) {
                const maxIdx = this.deque.peekFront();
                const maxVal = nums[maxIdx];
                log(`Window full. Current max is input[${maxIdx}] = ${maxVal}`);
                this.arr.highlight(maxIdx, '#10b981');
                result.push(maxVal);
                this.res.init(result);
                this.res.highlight(result.length - 1, '#10b981');
                await awaitStep();
                this.arr.render();
                this.arr.highlight(i, '#3b82f6');
            }

            await awaitStep();
            this.deque.clearHighlights();
        }

        log('Sliding Window Max complete.');
    }
}
